// beginTime 往前 padding（仅在“原始时长 <= 2分钟”时使用）
const preSeconds = 5;

// endTime 往后 padding（永远叠加）
const postSeconds = 2;

// 超过两分钟时：只取 endTime 往前 2分钟
const tailSeconds = 120;

// 兼容：字段可能在 $json 或 $json.body
const src = $json.body ?? $json;

const beginTime = src.beginTime;
const endTime = src.endTime;

if (!beginTime || !endTime) {
  throw new Error(
    `Missing beginTime/endTime. Got keys: ${Object.keys(src).join(', ')}; ` +
    `beginTime=${beginTime}, endTime=${endTime}`
  );
}

// 解析 "YYYY-MM-DD HH:mm:ss.SSS" 为 +08:00 时间
function parseLocalMs(s) {
  if (typeof s !== "string") throw new Error(`Time is not string: ${String(s)}`);
  const iso = s.replace(" ", "T") + "+08:00";
  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) throw new Error(`Invalid time: ${s}`);
  return d;
}

// 格式化回 "YYYY-MM-DD HH:mm:ss.SSS"
function fmtLocalMs(d) {
  const t = new Date(d.getTime() + 8 * 3600 * 1000);
  const yyyy = t.getUTCFullYear();
  const MM = String(t.getUTCMonth() + 1).padStart(2, "0");
  const dd = String(t.getUTCDate()).padStart(2, "0");
  const hh = String(t.getUTCHours()).padStart(2, "0");
  const mm = String(t.getUTCMinutes()).padStart(2, "0");
  const ss = String(t.getUTCSeconds()).padStart(2, "0");
  const SSS = String(t.getUTCMilliseconds()).padStart(3, "0");
  return `${yyyy}-${MM}-${dd} ${hh}:${mm}:${ss}.${SSS}`;
}

const b = parseLocalMs(beginTime);
const e = parseLocalMs(endTime);

if (e.getTime() < b.getTime()) {
  throw new Error(`endTime < beginTime: begin=${beginTime}, end=${endTime}`);
}

const rawSeconds = (e.getTime() - b.getTime()) / 1000;

// endTime2 永远按 postSeconds 往后叠加
let end2 = new Date(e.getTime() + postSeconds * 1000);

// beginTime2：
// - 若原始时长 > 2分钟：begin2 = endTime 往前 2分钟（只取尾段）
// - 否则：begin2 = beginTime 往前 preSeconds
let begin2;
let usedTail2Min = false;

if (rawSeconds > tailSeconds) {
  begin2 = new Date(e.getTime() - tailSeconds * 1000);
  usedTail2Min = true;
} else {
  begin2 = new Date(b.getTime() - preSeconds * 1000);
}

// 诊断字段：最终窗口秒数
const windowSeconds = (end2.getTime() - begin2.getTime()) / 1000;

// ---- Task Result 前缀：生成 event_id2 ----
const taskResultRaw = src["Task Result"] ?? "UNK";
const taskResult = String(taskResultRaw).trim() || "UNK";
const resultPrefix = taskResult.replace(/[^\w-]+/g, "_");
const event_id2 = `${resultPrefix}_${src.event_id}`;

// 输出：保留原字段，同时新增 beginTime2/endTime2，以及诊断字段 + event_id2
return [
  {
    ...$json,
    beginTime,
    endTime,
    preSeconds,
    postSeconds,
    tailSeconds,
    rawSeconds,
    usedTail2Min,          // ✅ 是否触发“超过两分钟取尾段2分钟”
    windowSeconds,
    beginTime2: fmtLocalMs(begin2),
    endTime2: fmtLocalMs(end2),

    event_id: src.event_id,
    event_id2,
    taskResult,
    resultPrefix,
    Deepmind: src.Deepmind,
    Channel: src.Channel,
  },
];
